// Collect outputs from both Notion and Jira nodes
const notionData = $('Notion — Get All RC1 Tasks').first().json;
const jiraItems = $('Jira — Get This Week\'s Updates').all();

// Process Notion pages
const pages = notionData.results || [];
const taskSummary = pages.map(p => {
  const props = p.properties || {};
  return {
    name: props.Name?.title?.[0]?.plain_text || 'Untitled',
    jiraKey: props['Jira Key']?.rich_text?.[0]?.plain_text || '',
    status: props.Status?.select?.name || 'Unknown',
    priority: props.Priority?.select?.name || 'Unknown',
    assignee: props.Assignee?.rich_text?.[0]?.plain_text || 'Unassigned'
  };
});

// Group by status
const done = taskSummary.filter(t => t.status === 'Done');
const inProgress = taskSummary.filter(t => t.status === 'In Progress');
const inReview = taskSummary.filter(t => t.status === 'In Review');
const toDo = taskSummary.filter(t => t.status === 'To Do');
const blocked = taskSummary.filter(t => t.status === 'Blocked');

// Process Jira updates this week
const weeklyUpdates = jiraItems.map(i => ({
  key: i.json.key,
  summary: i.json.fields?.summary,
  status: i.json.fields?.status?.name,
  assignee: i.json.fields?.assignee?.displayName || 'Unassigned'
}));

// Calculate overall health
const total = taskSummary.length;
const doneCount = done.length;
const blockedCount = blocked.length;
const completionPct = total > 0 ? Math.round((doneCount / total) * 100) : 0;

let health = '🟢 On Track';
if (blockedCount > 0) health = '🔴 At Risk';
else if (completionPct < 50 && inProgress.length === 0) health = '🟡 Needs Attention';

// Build data payload for Claude
return [{
  json: {
    health,
    completionPct,
    total,
    doneCount,
    inProgressCount: inProgress.length,
    blockedCount,
    done,
    inProgress,
    inReview,
    toDo,
    blocked,
    weeklyUpdates,
    reportDate: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  }
}];

