// Extract Claude's response and parse subject + body
const response = $input.first().json;
const text = response.content?.find(b => b.type === 'text')?.text || '';

// Split subject from body
const subjectMatch = text.match(/SUBJECT:\s*(.+?)\n/);
const subject = subjectMatch ? subjectMatch[1].trim() : 'AI Incident Summarizer — Weekly Status Update';
const body = text.replace(/SUBJECT:\s*.+?\n/, '').trim();

// Convert newlines to HTML for email
const htmlBody = body
  .split('\n')
  .map(line => `<p>${line}</p>`)
  .join('')
  .replace(/<p><\/p>/g, '<br/>');

return [{
  json: {
    subject,
    body,
    htmlBody
  }
}];

